"use client";

import TeacherDNA from "@/components/teacher/TeacherDNA";
import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import Layout from "@/components/Layout";

export default function TeacherDetailsPage() {

  const params = useParams();

  const [data, setData] =
    useState<any>(null);

  useEffect(() => {
    if (params?.id) {
      loadTeacher();
    }
  }, [params]);

  const loadTeacher =
    async () => {

      const response =
        await fetch(
          `/api/teachers/${params.id}`
        );

      const result =
        await response.json();

      setData(result);
    };

  if (!data) {
    return (
      <Layout>
        <div className="p-10">
          Loading Teacher...
        </div>
      </Layout>
    );
  }

  const {
    teacher,
    attendancePercent,
    experienceScore,
    impactScore,
    rating,
teacherDNA,
  } = data;

  return (
    <Layout>

      <div className="space-y-8">

        <div className="bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-3xl p-10">

          <h1 className="text-5xl font-black">
            👨‍🏫 Teacher Intelligence
          </h1>

          <p className="text-xl mt-3">
            AI Powered Faculty Insights
          </p>

        </div>

        <div className="bg-white rounded-3xl p-8 shadow">

          <div className="flex items-center gap-6">

            <div className="w-32 h-32 rounded-full bg-indigo-100 flex items-center justify-center text-6xl">
              👨‍🏫
            </div>

            <div>

              <h2 className="text-4xl font-black">
                {teacher.first_name}
                {" "}
                {teacher.last_name}
              </h2>

              <p>
                Employee:
                {" "}
                {teacher.employee_id}
              </p>

              <p>
                {teacher.designation}
              </p>

              <p>
                {teacher.department}
              </p>

            </div>

          </div>

        </div>

        <div className="grid lg:grid-cols-5 gap-6">

          <div className="bg-white p-6 rounded-3xl shadow">

            <p>Impact Score</p>

            <h2 className="text-5xl font-black">
              {impactScore}
            </h2>

          </div>

          <div className="bg-white p-6 rounded-3xl shadow">

            <p>Attendance</p>

            <h2 className="text-5xl font-black">
              {attendancePercent}%
            </h2>

          </div>

          <div className="bg-white p-6 rounded-3xl shadow">

            <p>Experience Score</p>

            <h2 className="text-5xl font-black">
              {experienceScore}
            </h2>

          </div>
<div className="bg-white p-6 rounded-3xl shadow">

  <p>Teacher Health</p>

  <h2 className="text-5xl font-black text-purple-600">
    {Math.round(
      attendancePercent * 0.5 +
      impactScore * 0.5
    )}
  </h2>

</div>


          <div className="bg-white p-6 rounded-3xl shadow">

            <p>Rating</p>

            <h2 className="text-3xl font-black">
              {rating}
            </h2>

          </div>

        </div>

<div className="bg-white p-6 rounded-3xl shadow">

  <p>Burnout Risk</p>

  <h2 className="text-3xl font-black text-red-600">
    {teacherDNA?.burnoutRisk}
  </h2>

</div>


        <div className="grid grid-cols-2 gap-6">

          <div className="bg-white p-8 rounded-3xl shadow">

            <h2 className="text-2xl font-bold mb-4">
              Faculty Details
            </h2>

            <p>
              Email:
              {" "}
              {teacher.email}
            </p>

            <p>
              Phone:
              {" "}
              {teacher.phone}
            </p>

            <p>
              Qualification:
              {" "}
              {teacher.qualification}
            </p>

            <p>
              Experience:
              {" "}
              {teacher.experience_years}
              {" "}Years
            </p>

            <p>
              Salary:
              {" "}
              ₹{teacher.salary}
            </p>

          </div>

          <div className="bg-white p-8 rounded-3xl shadow">

            <h2 className="text-2xl font-bold mb-4">
              AI Recommendations
            </h2>

            <ul className="space-y-3">

              <li>
                ✅ Continue mentoring
                high-performing students
              </li>

              <li>
                ✅ Maintain attendance
                consistency
              </li>

              <li>
                ✅ Conduct advanced
                workshops
              </li>

              <li>
                ✅ Share best practices
                with faculty
              </li>

            </ul>

          </div>

        </div>

<div className="bg-white rounded-3xl p-8 shadow">

  <h2 className="text-3xl font-black mb-6">
    Teacher DNA
  </h2>

  <TeacherDNA
    dna={teacherDNA}
  />

</div>


      </div>

    </Layout>
  );
}
